Here's a minimal API endpoint handling multipart form uploads with multiple images and a description:

```csharp
using Microsoft.AspNetCore.Http.Features;

var builder = WebApplication.CreateBuilder(args);

// Increase the max request body size to 50 MB
builder.WebHost.ConfigureKestrel(options =>
{
    options.Limits.MaxRequestBodySize = 50 * 1024 * 1024;
});

var app = builder.Build();

app.MapPost("/upload", async (HttpRequest request) =>
{
    // Ensure it's a multipart form request
    if (!request.HasFormContentType)
        return Results.BadRequest("Expected a multipart form request.");

    var form = await request.ReadFormAsync();
    var description = form["description"].ToString();
    var files = form.Files.GetFiles("images");

    if (files.Count == 0)
        return Results.BadRequest("No image files provided.");

    var uploadPath = Path.Combine(Directory.GetCurrentDirectory(), "uploads");
    Directory.CreateDirectory(uploadPath);

    var saved = new List<string>();

    foreach (var file in files)
    {
        if (!file.ContentType.StartsWith("image/"))
            return Results.BadRequest($"File '{file.FileName}' is not an image.");

        var fileName = $"{Guid.NewGuid()}{Path.GetExtension(file.FileName)}";
        var filePath = Path.Combine(uploadPath, fileName);

        await using var stream = File.Create(filePath);
        await file.CopyToAsync(stream);

        saved.Add(fileName);
    }

    return Results.Ok(new { description, fileCount = saved.Count, fileNames = saved });
})
.DisableAntiforgery()                       // required for minimal APIs accepting forms without tokens
.WithName("UploadImages");

app.Run();
```

**Key points:**

- `ConfigureKestrel` raises the body size limit to 50 MB (default is ~30 MB).
- Files are read from the form via `form.Files.GetFiles("images")` — the client sends them under the field name `images`.
- `.DisableAntiforgery()` is needed in .NET 8 minimal APIs when accepting form data without an antiforgery token.
- A basic content-type check rejects non-image files.

**Example `curl` to test it:**

```bash
curl -X POST http://localhost:5000/upload \
  -F "description=My vacation photos" \
  -F "images=@photo1.jpg" \
  -F "images=@photo2.png"
```
